// // This JK latch toggles on the clock edge when J and K are both high, sets to 1 when J is high and K is low, and resets to 0 when J is low and K is high.
module JK_latch (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && K)  
            Q <= ~Q;  
        else if (J)  
            Q <= 1;  
        else if (K)  
            Q <= 0;  
    end  
endmodule
